<?php if (!defined('ABSPATH')) exit; get_header(); $s = get_search_query(); ?>
<div class="flavor-container py-8"><h1 class="text-4xl font-bold mb-6">Búsqueda: "<?php echo esc_html($s); ?>"</h1><?php $q = new WP_Query(array('post_type' => 'biblioteca', 's' => $s)); if ($q->have_posts()) : echo '<div class="grid md:grid-cols-4 gap-6">'; while ($q->have_posts()) : $q->the_post(); $autor = get_post_meta(get_the_ID(), '_autor', true); echo '<article class="bg-white rounded-xl shadow-md overflow-hidden">'; if (has_post_thumbnail()) the_post_thumbnail('medium', array('class' => 'w-full aspect-[2/3] object-cover')); echo '<div class="p-4"><h2 class="text-lg font-bold mb-2"><a href="' . get_permalink() . '">' . get_the_title() . '</a></h2>'; if ($autor) echo '<p class="text-sm text-gray-600">' . esc_html($autor) . '</p>'; echo '<a href="' . get_permalink() . '" class="mt-3 block text-center px-4 py-2 bg-primary text-white rounded-lg text-sm">Ver</a></div></article>'; endwhile; echo '</div>'; else : echo '<div class="text-center py-16"><h3 class="text-2xl font-bold">Sin resultados</h3></div>'; endif; wp_reset_postdata(); ?></div><?php get_footer(); ?>
